async function handleRecordRuntimeEvent(req: IncomingMessage, res: ServerResponse, parsed: ParsedProjectParam): Promise<void> {
  const project = await loadProject(parsed, req);
  enforceWriteRateLimit(req, project.id);
  const tenantId = await resolveTenantId(project);
  const body = await readJson(req);
  const eventType = normalizeWidgetRuntimeEventType(body.eventType || body.event_type);
  if (!eventType) {
    throw Object.assign(new Error('Unsupported widget runtime event type.'), {
      status: 400,
      code: 'UNSUPPORTED_RUNTIME_EVENT',
    });
  }

  const safeContextBody = {
    ...body,
    metadata: {},
  };
  const eventMetadata = {
    ...safeVoiceRuntimeMetadata(body),
    ...getWidgetContextMetadata(safeContextBody),
  };
  const evaluation = await assertWidgetChatbotActionAllowed(req, project, tenantId, safeContextBody, {
    actionType: 'record_analytics_event',
    idempotencyKey: normalizeString(body.idempotencyKey, 240),
    idempotencyParts: [
      eventType,
      normalizeString(body.sessionId, 120),
      normalizeString(body.sessionPhase, 80),
      normalizeString(body.reason, 160),
    ],
    metadata: eventMetadata,
  });

  await recordWidgetChatbotEngineEvent(buildChatbotEngineObservedEvent({
    tenantId: project.tenant_id,
    projectId: project.id,
    actionType: 'record_analytics_event',
    eventType,
    sourceSurface: getWidgetSourceSurface(safeContextBody),
    sourceModule: getWidgetSourceModule(safeContextBody),
    conversationId: normalizeString(body.sourceConversationId, 120) || normalizeString(body.conversationId, 120),
    idempotencyKey: evaluation.idempotencyKey,
    correlationId: normalizeString(body.correlationId, 240),
    requestFingerprint: getRequestFingerprint(req, project.id),
    metadata: {
      ...eventMetadata,
      actionRegistryAllowed: evaluation.allowed,
      actionRegistryReason: evaluation.reason,
    },
  }));

  send(res, 202, { recorded: true, eventType });
}

async function handleCreateVoiceSession(req: IncomingMessage, res: ServerResponse, parsed: ParsedProjectParam): Promise<void> {
  const project = await loadProject(parsed, req, true, { requireAssistant: true });
  enforceWriteRateLimit(req, project.id);
  const tenantId = await resolveTenantId(project);
  const body = await readJson(req);
  const sessionId = normalizeString(body.sessionId, 120) || randomUUID();
  const conversationId = normalizeString(body.sourceConversationId, 120) || normalizeString(body.conversationId, 120);
  const consentAccepted = getWidgetVoiceConsentAccepted(body);
  const safeActionBody = {
    ...body,
    sourceSurface: 'voice',
    sourceModule: getWidgetSourceModule(body),
    metadata: {},
  };
  const voiceSettings = resolveWidgetVoiceSettings(project);
  const readiness = getChatCoreVoiceSessionReadiness(voiceSettings, consentAccepted);
  const voiceMetadata = {
    widgetApi: true,
    runtimeEvent: true,
    sessionId,
    sessionPhase: readiness.allowed ? 'requested' : 'blocked',
    voice: {
      provider: voiceSettings.provider,
      source: voiceSettings.source,
      languageMode: voiceSettings.languageMode,
      consentRequired: voiceSettings.consentRequired,
      consentAccepted,
      agentConfigured: Boolean(voiceSettings.agentId),
    },
    agentIdRedactedFromEvent: true,
  };

  const voiceAction = await assertWidgetChatbotActionAllowed(req, project, tenantId, safeActionBody, {
    actionType: 'record_analytics_event',
    idempotencyKey: normalizeString(body.idempotencyKey, 240),
    idempotencyParts: [
      'voice-session',
      sessionId,
      conversationId,
      consentAccepted,
      readiness.reason,
    ],
    metadata: {
      ...voiceMetadata,
      runtimeEventType: readiness.allowed
        ? 'chatbot_voice_session_requested'
        : 'chatbot_voice_session_blocked',
    },
  });

  if (!readiness.allowed) {
    await recordWidgetChatbotEngineEvent(eventWithResult(voiceAction.auditEvent, {
      event_type: 'chatbot_voice_session_blocked',
      conversation_id: conversationId || undefined,
    }, 'blocked', {
      ...voiceMetadata,
      runtimeEventType: 'chatbot_voice_session_blocked',
      reason: readiness.reason,
      readinessReason: readiness.reason,
      providerSessionStarted: false,
    }));

    send(res, readiness.reason === 'consent_required' ? 403 : 409, {
      allowed: false,
      reason: readiness.reason,
      sessionId,
      provider: voiceSettings.provider,
      source: voiceSettings.source,
      languageMode: voiceSettings.languageMode,
      consentRequired: voiceSettings.consentRequired,
      agentConfigured: Boolean(voiceSettings.agentId),
    });
    return;
  }

  await recordWidgetChatbotEngineEvent(eventWithResult(voiceAction.auditEvent, {
    event_type: 'chatbot_voice_session_requested',
    conversation_id: conversationId || undefined,
  }, 'executed', {
    ...voiceMetadata,
    runtimeEventType: 'chatbot_voice_session_requested',
    providerSessionStarted: false,
  }));

  send(res, 201, {
    allowed: true,
    sessionId,
    provider: voiceSettings.provider,
    source: voiceSettings.source,
    agentId: voiceSettings.agentId,
    languageMode: voiceSettings.languageMode,
    consentRequired: voiceSettings.consentRequired,
    eventRedaction: {
      agentId: true,
    },
  });
}

async function handleUpdateConversation(req: IncomingMessage, res: ServerResponse, parsed: ParsedProjectParam, conversationId: string): Promise<void> {
  const project = await loadProject(parsed, req);
  enforceWriteRateLimit(req, project.id);
  const body = await readJson(req);
  const participantInfo = body.participantInfo && typeof body.participantInfo === 'object' ? body.participantInfo : {};
  const widgetContextMetadata = getWidgetContextMetadata(body);
  const sourceSurface = getWidgetSourceSurface(body);
  const sourceModule = getWidgetSourceModule(body);

  const name = normalizeString(participantInfo.name, 200);
  const email = normalizeString(participantInfo.email, 320);
  const phone = normalizeString(participantInfo.phone, 80);
  const avatarUrl = normalizeString(participantInfo.avatarUrl, 1000) || normalizeString(participantInfo.avatar, 1000);
  const leadId = normalizeString(body.leadId, 120);
  const status = normalizeString(body.status, 40);
  const validStatus = status && ['active', 'closed', 'pending', 'escalated'].includes(status)
    ? status as 'active' | 'closed' | 'pending' | 'escalated'
    : null;
  const now = new Date().toISOString();
  const metadata = {
    widgetApi: true,
    endpoint: 'api/widget',
    requestFingerprint: getRequestFingerprint(req, project.id),
    ...widgetContextMetadata,
  };
  const commonInput = {
    tenantId: project.tenant_id,
    projectId: project.id,
    conversationId,
    participantInfo: {
      name: name || null,
      email: email || null,
      phone: phone || null,
      avatarUrl: avatarUrl || null,
    },
    status: validStatus,
    sourceSurface,
    sourceModule,
    chatbotEngineContext: widgetContextMetadata.chatbotEngineContext as any,
    metadata,
    tags: ['web-chat'],
    correlationId: normalizeString(body.correlationId, 240),
    actorType: 'visitor' as const,
    now,
  };

  const participantChanged = Boolean(name || email || phone || avatarUrl || validStatus || !leadId);
  const participantResult = participantChanged
    ? await updateConversationParticipant({
      ...commonInput,
      idempotencyKey: normalizeString(body.idempotencyKey, 240),
    }, getSupabaseAdmin())
    : null;
  const leadResult = leadId
    ? await linkConversationToLead({
      ...commonInput,
      leadId,
      idempotencyKey: normalizeString(body.leadIdempotencyKey, 240)
        || normalizeString(body.idempotencyKey, 240),
    }, getSupabaseAdmin())
    : null;

  send(res, 200, {
    ok: true,
    conversationId,
    leadId: leadResult?.leadId || leadId || null,
    messageCount: leadResult?.messageCount ?? participantResult?.messageCount,
    warnings: [
      participantResult?.warning,
      leadResult?.warning,
    ].filter(Boolean),
  });
}

